    # Enumerate a range of t values to generate points (tan t, sec t)
    import math
    points = []
    for i in range(1, 100):
        t = i * 0.1
        if abs(math.cos(t)) > 1e-10:  # Avoid division by zero
            x = math.tan(t)
            y = 1 / math.cos(t)
            points.append((x, y))

    # Check the nature of the curve by testing algebraic relationships
    # For a hyperbola: y^2 - x^2 = 1 (using sec^2 t - tan^2 t = 1)
    is_hyperbola = True
    for x, y in points:
        if abs(y**2 - x**2 - 1) > 1e-6:
            is_hyperbola = False
            break

    # For other conics, check their standard forms
    is_parabola = True
    for x, y in points:
        # Parabola: y = a*x^2 + b*x + c or x = a*y^2 + b*y + c
        # We test a simple form like y = a*x^2 + b
        # This is not general, so we expect it to fail unless it's actually a parabola
        if abs(y - (x**2 + 1)) > 1e-6 and abs(y + (x**2 + 1)) > 1e-6:
            is_parabola = False
            break

    is_circle = True
    for x, y in points:
        # Circle: x^2 + y^2 = r^2
        if abs(x**2 + y**2 - 2) > 1e-6:
            is_circle = False
            break

    is_ellipse = True
    for x, y in points:
        # Ellipse: (x/a)^2 + (y/b)^2 = 1
        if abs((x**2)/1 + (y**2)/2 - 1) > 1e-6:
            is_ellipse = False
            break

    is_line = True
    for x, y in points:
        # Line: y = mx + c
        if abs(y - x) > 1e-6 and abs(y + x) > 1e-6:
            is_line = False
            break

    # Determine the correct option
    if is_hyperbola:
        correct = 'E'
    elif is_parabola:
        correct = 'C'
    elif is_circle:
        correct = 'B'
    elif is_ellipse:
        correct = 'D'
    elif is_line:
        correct = 'A'
    else:
        correct = 'E'  # Default to hyperbola if none match

    return ans == correct

