from sympy import symbols, solve

def verify(answer):
    try:
        ans = int(str(answer).strip())
    except Exception:
        return False

    # Define the polynomial and solve for roots
    x = symbols('x')
    poly = x**3 - 20*x**2 + 18*x - 7
    roots = solve(poly, x)

    if len(roots) != 3:
        return False

    r, s, t = roots[0], roots[1], roots[2]

    # Compute r^2s^2 + s^2t^2 + t^2r^2
    expr = r**2 * s**2 + s**2 * t**2 + t**2 * r**2

    # Evaluate the expression numerically to handle symbolic roots
    try:
        value = expr.simplify()
        if value.is_number:
            return int(value) == ans
        else:
            # If symbolic evaluation doesn't resolve, fallback to numerical
            num_value = float(value.evalf())
            return abs(num_value - ans) < 1e-6
    except Exception:
        return False

